c
void execute(VM* vm) {
while (vm->running) {
// 1. Fetch opcode and post-increment IP
uint8_t op = vm->bytecode[vm->ip++];

pre.code:
    switch (op) {
        case OP_LDC: {
            // 2. Helper read16() handles IP advancement (+2)
            uint16_t idx = read16(vm); 
            push(vm->stack, vm->constants[idx]);
            break;
        }
        case OP_JMP: {
            // 3. Absolute write to IP
            vm->ip = read16(vm); 
            break;
        }
        case OP_HALT:
            vm->running = false;
            break;
    }
}
